var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"자, 약속한 대로야. 네가 준비한 명의로 시장에 나온 퓨처 앳 워의 지분을 모두 사들였어.","JPN":"さあ、約束したとおりよ。あんたが用意した名義で市場に出されたフューチャーアットウォーの株をすべて買収したわ。","ENG":"Here, as promised. I bought all of the Future-at-War stocks in the market with the account you gave me.","TWN":"按照約定，我已經用你準備的身分，買下天啟兵器在市面上所有的股份，"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"이제 우리 회사는 퓨처 앳 워 재단의 최대 주주야.","JPN":"もう我が社はフューチャーアットウォー財団の筆頭株主よ。","ENG":"Now, we are the majority shareholder of the Future-at-War Foundation.","TWN":"現在我們公司是天啟兵器財團的最大股東！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"덕분에 회사가 보유한 현금을 거의 다 써버렸지만.","JPN":"おかげで会社が保有していた現金をほとんど使い果たしてしまったけどね。","ENG":"Although, thanks to that, we used up all of the company’s cash reserve.","TWN":"不過也因為這樣，公司所有的現金幾乎花得一毛不剩。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"어때? 돈지랄을 한 기념으로 샴페인이나 터뜨려 볼까?","JPN":"どう？　財産を使い果たした記念にシャンパンでも開ける？","ENG":"So? How about we pop open a bottle of champagne in celebration?","TWN":"如何？要開個香檳慶祝一下把錢花光光嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"샴페인이라…… 좋은 생각이군.","JPN":"シャンパンか……いい考えだ。","ENG":"Champagne, eh? Great idea.","TWN":"香檳嗎……這個點子不錯。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"수고했네, <color=#ffd34c>갬블러</color>. 자네 덕분에 세상의 흐름을 다시 한 번 바꿀 수 있게 됐어.","JPN":"ご苦労だった、<color=#ffd34c>ギャンブラー</color>。君のおかげで世界の流れを\\nもう一度変えられるようになったよ。","ENG":"Good job, <color=#ffd34c>Gambler</color>. Thanks to you, we can change the flow of the world once again.","TWN":"辛苦你了，<color=#ffd34c>賭徒</color>。托你的福，才能再次改變世界的潮流。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"세상의 흐름……? 언제나처럼 무슨 소릴 하는지 모를 녀석이군.","JPN":"世界の流れ……？　いつものことだけど、ほんと何言ってるのか\\nわからないやつね。","ENG":"The flow of the world...? As usual, I have no idea what you’re talking about.","TWN":"世界的潮流……？你還是一如往常地講些我聽不懂的話。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"그런데 왜 갑자기 내게 퓨처 앳 워 재단을 인수하라고 한 거지?","JPN":"ところで、どうして急にフューチャーアットウォー財団を買収しろなんて言ったの？","ENG":"Hey Sysop, why did you ask me to buy all those shares of Future-at-War?","TWN":"不過為什麼突然要我收購天啟兵器財團？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"기술력은 뛰어나지만 하나같이 채산성이 부족한 것들 뿐이잖아, 시솝.","JPN":"技術力は優れているけど、採算性に乏しいものばかりじゃない、シソップ？","ENG":"I know their technology is great and all, but most of it can’t even turn a profit.","TWN":"他們的技術確實很不錯，可是一樣利潤不佳不是嗎，錫索普？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"뭔가 좋은 정보라도 들어온 건가?","JPN":"何かいい情報でも入ってきたの？","ENG":"Did someone give you the inside scoop or something?","TWN":"還是你有得到什麼內線消息？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"아니, 그저 <color=#ffd34c>새로운 친구</color>를 위한 환영 선물이 필요했을 뿐이야.","JPN":"いや、ただ<color=#ffd34c>新たな仲間</color>のための歓迎プレゼントが必要だっただけだ。","ENG":"No. I just needed a welcoming present for my <color=#ffd34c>new friend</color>.","TWN":"沒有，只是需要為<color=#ffd34c>新朋友</color>準備禮物而已。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"퓨처 앳 워 재단에서 동결한 비밀 기술을 오랫동안 찾아다니던 친구거든.","JPN":"彼女はフューチャーアットウォー財団で凍結した秘密技術を、\\n長い間探していたからな。","ENG":"She has been looking for some secret technology that Future-at-War has put on hold for a long time.","TWN":"他一直在找天啟兵器藏起來的秘密技術。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"새로운 친구?","JPN":"新たな仲間？","ENG":"New friend?","TWN":"新朋友？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"이봐, 예전부터 말해주고 싶었는데 넌 좀 친구를 가려 사귈 필요가 있어.","JPN":"ねえ、前から言おうと思ってたけど、仲間はもう少し慎重に\\n選んだほうがいいわよ。","ENG":"You know, I’ve been meaning to tell you, but you really need to make some better friends.","TWN":"喂，我從以前就很想跟你說，拜託你交朋友的時候也挑一下吧！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"그 성냥팔이란 녀석이나 헤이븐이나……","JPN":"あのマッチ売りとかいうのもそうだし、ヘイブンだって……","ENG":"Like that Matchmaker or Haven...","TWN":"那個什麼賣火柴的，還有什麼天堂的……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"그런 떨거지들을 다 친구로 받아주면 세상이 우릴 우습게 여기게 된다고.","JPN":"あんな小者どもまで仲間として受け入れてたら、周りから舐められるわよ。","ENG":"If you make friends with those losers, you’ll be the laughingstock of the whole world.","TWN":"你跟那種下三濫交朋友，人家會瞧不起我們的！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"하하, 타인에 대한 자네의 평가 기준은 언제나 엄격하군.","JPN":"はは、他人に対する君の評価は相変わらず厳しいな。","ENG":"Haha. Your standards for judging others are always so strict.","TWN":"哈哈，你對別人的標準總是很嚴苛呢！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"하지만…… 그 기준을 자신에게 적용하면 어떨지 궁금하지 않나?","JPN":"しかし……その基準を自分に適用したらどうなるか、気にならないか？","ENG":"But... Aren’t you curious what will happen if I apply the same standards onto you?","TWN":"但……用你那套標準來看你自己呢？不覺得很好奇嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"뭐? 무, 무슨 말을 하는 거야!","JPN":"は？　な、何が言いたいのよ！","ENG":"Huh? W-what are you trying to say, huh?!","TWN":"什麼？你什麼意思！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"지금 자네의 모습을 보게.","JPN":"今の君の姿を見ろ。","ENG":"Just look at yourself.","TWN":"你看看你現在的樣子。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"도박에 실패한 겜블러라니, 정말이지 훌륭한 떨거지가 아닌가.","JPN":"ギャンブルに失敗したギャンブラーとは、まったく立派な小者じゃないか。","ENG":"You’re a gambler who loses every time. What more of a loser can I expect?","TWN":"一個賭輸的賭徒，不就是名符其實的下三濫嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"시, 시끄러! 그딴 게 느닷없이 튀어나올 줄 누가 알았냐고!","JPN":"う、うるさい！　あんなモノがいきなり出てくるなんて誰も予想できないでしょ！","ENG":"S-shut up! I didn’t know that would appear out of nowhere!","TWN":"你閉嘴！誰知道那個會莫名其妙冒出來！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"그 어린 년의 수법은 모두 파악했어!","JPN":"あの小娘の手口はすべて把握したわ！","ENG":"But I got her all figured out now!","TWN":"我已經看破那丫頭的伎倆！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"다음 대국에서는 단숨에 승리를 거머쥘 거라고!","JPN":"次の対局では一気に勝利してやるから！","ENG":"I’m sure to win the next time!","TWN":"在下次的棋局裡，我一定會一鼓作氣拿下勝利！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"다음 대국? 분명 이번이 모든 것을 건 마지막 승부라고 들었던 것 같은데?","JPN":"次の対局？　確か今回がすべてを賭けた最後の勝負だと聞いた気がするが？","ENG":"Next time? I thought you said you were all in on this one?","TWN":"下次的棋局？你不是說這次是賭上你的全部家當嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"참견하지 마. 잠깐 대표 명의를 양도했다고 해서 내가 네 부하라도 되는 것 같아?","JPN":"口出ししないで。ちょっと代表名義を譲ったからって、\\n私があんたの部下だとでも思ってるの？","ENG":"Shut up. Just because I put you in charge temporarily doesn’t mean I’m your subordinate now, okay?","TWN":"不關你的事，不要以為你把代表的名義讓給我，就以為我是你的手下。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"우린 각자 서로의 영역을 존중해 주기로 했을 텐데?","JPN":"私たちはそれぞれお互いの領域を尊重することにしたはずだけど？","ENG":"We both decided to respect each other’s work, didn’t we?","TWN":"不是說好要尊重各自的領域嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"아무리 의장이라도 함부로 선을 넘는 건 용납할 수 없어.","JPN":"いくら議長でも、一線を越えてくるのは容認できないわ。","ENG":"Even if you're the chairman, I won't let you cross the line.","TWN":"就算是主席，我也無法容忍越界的行為。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"그보다 확실하겠지?","JPN":"それより、本当なの？","ENG":"Anyway, are you certain about this?","TWN":"不過你確定嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"이 좌표에 숨어 있으면 관리국도 알파트릭스도 날 찾아내지 못할 거라는 말.","JPN":"この座標に隠れていれば、管理局もアルファトリックスも\\n私を見つけられないってこと。","ENG":"You stated that if I hide at this coordinate, neither the Administration nor Alphatrix will be able to locate me.","TWN":"只要躲在這個座標，不管是管理局，或是阿爾法崔克斯，誰都找不到我對吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"아, 그야 물론이지.","JPN":"ああ、もちろんだ。","ENG":"I’m absolutely sure.","TWN":"這是當然的。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"관리국도, 알파트릭스도…… 존재하지 않는 사람을 찾아낼 방법은 없을 테니까.","JPN":"管理局もアルファトリックスも……存在しない人を捜し出す方法は\\nないだろうからな。","ENG":"Nobody can find someone who doesn’t exist. Even if it’s the Administration or Alphatrix.","TWN":"不管是管理局，或是阿爾法崔克斯……當然都沒辦法找到一個不存在的人。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"뭐? 지금 무슨 소리를……?","JPN":"なに？　それはどういう意味……？","ENG":"Huh? What are you talking...?","TWN":"這什麼意……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"뭐, 뭐야? 이건? 지진……?","JPN":"え、何これ？　地震……？","ENG":"H-huh…? Is this... an earthquake?","TWN":"搞什麼？這是怎樣？地震……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"말도 안 돼……. 설마 새 친구라는 게…….","JPN":"あり得ないわ……まさか、新たな仲間っていうのは……","ENG":"No way... Your new friend is a...","TWN":"怎麼可能……難道你說的新朋友就是……"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"나약한 탄소 기반 생물체의 시간은 내게 아무 의미가 없지만, 오랜만이라고 해야겠군.","JPN":"軟弱な炭素ベースの生物の時間は私にとって何の意味もないが、\\n久しぶりだと言っておこう。","ENG":"Although your weak carbon-based lifeforms' concept of time has no meaning to me, long time no see.","TWN":"雖然人類的時間對我而言不具任何意義，但這種時候，還是要說句好久不見吧？"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"서로 이런 꼴로 다시 보게 되어 유감이다. 회장.","JPN":"お互いこんな格好で再会することになるとは残念だな、会長。","ENG":"I’m sorry we met each other in these forms, President.","TWN":"沒想到再次見面，你和我都已經是不同的樣貌，會長。"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"어, 어떻게……? 내가 회장의 기억을 이식한 걸 알아챈 거지……!","JPN":"ど、どうして……？　私が会長の記憶を移植したことに気づいたの！？","ENG":"H-huh...? How did it know I had the President’s memories embedded in me...?!","TWN":"你…你怎麼……？你怎麼會知道我移植了會長的記憶……！"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"평생의 염원을 탄생시키는 데 성공했지만 말로가 실로 비참하군.","JPN":"一生の念願だったものを誕生させることには成功したが、\\n末路は実に悲惨だな。","ENG":"You achieved your lifelong ambition, but the outcome was truly dreadful.","TWN":"雖然你畢生的心血成功誕生，下場卻是如此淒涼。"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 네 머릿속에 있는 회장의 기억은 내 진화에 좋은 밑거름이 될 거다.","JPN":"しかし、お前の頭の中にある会長の記憶は、私の進化の良い糧になるだろう。","ENG":"Nonetheless, the President's memories in your head will serve as a solid foundation for my evolution.","TWN":"不過你腦袋裡面有關會長的記憶，可以成為我進化的養分。"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"오, 오지 마……!","JPN":"こ、来ないで……！","ENG":"S-stay back…!","TWN":"別…別過來……！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"오지 마!! 가까이 오지 말라고! 이 괴물이!!","JPN":"来ないでよ！！　近づかないで、この化け物！！","ENG":"Get away from me!! I said, back off!! You monster!!","TWN":"走開！！我叫你別過來！怪物！！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"흐음……. 악취미네, 의장.","JPN":"ふーん。悪趣味ね、議長。","ENG":"Hmm... That’s nasty, Sysop","TWN":"呵呵……這是主席的怪癖嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"음? 뭘 말인가?","JPN":"うむ？　何のことかね？","ENG":"Huh? What is?","TWN":"嗯？什麼意思？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"저 <color=#ffd34c>돈줄</color>을 쳐내지 않고 내버려 둔 이유가 이런 거였어?","JPN":"あの<color=#ffd34c>金づる</color>を見捨てずに残しておいた理由って\\nこれだったの？","ENG":"Is this why you didn’t remove that <color=#ffd34c>golden goose</color> until now?","TWN":"這就是你不把<color=#ffd34c>搖錢樹</color>處理掉，而是將她留下來的原因嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"우리에게 이 따위 우아하지도, 아름답지도 않은 결말을 보여 주려고?","JPN":"私たちにこんな優雅でもなく、美しくもない結末を見せようと？","ENG":"To show us her messed-up ending?","TWN":"想讓我們看到這既不又優雅也不美麗的結局？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"하하, 그럴 리가. 나는 그저 살짝 등을 밀어 줬을 뿐이야.","JPN":"ハハ、そんなわけない。私はただ、そっと背中を押しただけだ。","ENG":"Hah hah. Obviously not. I just nudged her back a bit.","TWN":"哈哈～怎麼會呢？我只是稍微推一把而已。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그들이 원래 다다라야 할 결말에 도달할 수 있게 말이지.","JPN":"彼らが本来たどり着くべき結末に到達できるようにね。","ENG":"So they got the ending they deserved.","TWN":"讓他們可以抵達原本該去的終點。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"내 아버지는…… 아쉽게도 이런 일에 적극적이지 않으시거든.","JPN":"我が父は……残念ながらこんなことに積極的ではないからな。","ENG":"My father... Unfortunately, he wasn’t very hands-on with this one.","TWN":"可惜……我父親對這種事不太積極。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그 잘난 애비가 누군지는 몰라도 사람을 장기말 취급하는 게 좋은 습관이 아니야.","JPN":"その父が誰なのかはわからないが、人を駒扱いするのは\\n良い趣味じゃないな。","ENG":"I'm not sure who your father is, but treating people like chess pieces is not a good habit.","TWN":"我是不清楚你那了不起的爸爸是誰，不過把人當棋子不是個很好的習慣。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"미리 말해 두는데, 우리에게도 그 따위 짓을 하려고 했다간 그 잘난 뒤통수에 납탄을 박아줄 거다, 애늙은이.","JPN":"先に言っておくが、俺らにもそんなふざけた真似をしようとするなら、\\nその偉そうな後頭部に鉛弾をぶち込んでやるからな、クソガキめ。","ENG":"Just so you know, if you try to pull something like that on us, I’ll gladly put a lead bullet in the back of that pretty little head, you old soul.","TWN":"我先把話說在前頭，你要是敢對我們那麼做，我會讓你的腦袋變蜂窩，聽到沒有，你這個老成的傢伙！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"걱정해 줘서 고맙군.","JPN":"ご心配どうも。","ENG":"Thanks for the heads up.","TWN":"謝謝你的提醒，"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"하지만 그럴 일은 없으니 걱정 말게나.","JPN":"でも、そんなことはしないから心配するな。","ENG":"But I assure you that will never happen.","TWN":"不過你大可以放心，你擔心的事是不會發生的。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"자네들은 비록 불완전하지만…… 세상의 흐름을 바꿀 수 있는 아주 중요한 존재이니까 말이야.","JPN":"君たちはたとえ不完全でも……世界の流れを変えることができる\\nとても重要な存在だからね。","ENG":"You all might be imperfect... But you are crucial in changing the flow of the world.","TWN":"你們雖然有缺陷……卻是改變世界潮流的重要元素。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"흠, 특별하게 생각해줘서 고맙다고 인사라도 들을 것 같아?","JPN":"ふん、特別と思ってくれてありがとうと、お礼でも言われたいのかしら？","ENG":"Hmm... Do you think I'll thank you for thinking of us as special?","TWN":"呵，你以為說這種話，我就會感謝你嗎？"},"stage":{"bg":"ALPHA_07","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"저 돈줄이 <color=#ffd34c>다다라야 할 결말</color>이라느니 뭐니……","JPN":"あの金づるが<color=#ffd34c>たどり着くべき結末</color>だなんて……","ENG":"All you ever do is talk about that golden goose finally <color=#ffd34c>getting the ending</color> she deserved...","TWN":"說什麼那個搖錢樹<color=#ffd34c>該抵達的終點</color>，還什麼的……"},"stage":{"bg":"ALPHA_07","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"매번 그렇게 삼류 예언자 같은 소리나 하고 있잖아.","JPN":"毎回そんな三流預言者みたいなことを言われてもね。","ENG":"You sound like one of those delusional prophets, you know that?","TWN":"每次都一副江湖術士的樣子，"},"stage":{"bg":"ALPHA_07","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"애초에 넌 정체가 뭐야?","JPN":"そもそも、あなたの正体は何なの？","ENG":"How about you tell us who you really are?","TWN":"你到底是誰？"},"stage":{"bg":"ALPHA_07","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"이젠 시솝 같은 웃기는 별명이 아니라 진짜 이름 정도는 말해줄 때가 되지 않았어?","JPN":"そろそろシソップみたいなふざけたあだ名じゃなくて、\\n本当の名前くらい教えてくれてもいいんじゃない？","ENG":"And don’t give us another stupid nickname like Sysop. Tell us what your real name is.","TWN":"還取個錫索普這麼可笑的外號，現在該告訴我們你真正的名字了吧？"},"stage":{"bg":"ALPHA_07","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"……오해가 있군.","JPN":"……誤解があるようだな。","ENG":"I believe you have a misunderstanding.","TWN":"……你誤會了。"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"시솝이라는 이름은 단순한 별명이 아니야.","JPN":"シソップという名は単なるあだ名ではない。","ENG":"Sysop is not just a stupid nickname.","TWN":"錫索普不只是個外號。"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"……응?","JPN":"……ん？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"잠깐, 너 등 뒤에 그 기계는……","JPN":"おいお前。その後ろの機械は……","ENG":"Wait... That machine on your back...","TWN":"你身後…那個機器是……"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그것은 내 본질을 가장 잘 설명하는 단어들 중 하나.","JPN":"それは私の本質を最も正しく説明する単語の一つ。","ENG":"Sysop is a word that best describes who I am.","TWN":"這個名字是最符合我本質的單字之一。"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"한 때 아버지를 도와 세상이라는 시스템을 조율했던 자에게 주어지는 칭호지.","JPN":"かつては父を助け、世界というシステムを調整した者に与えられる称号だ。","ENG":"It is also the title given to whatever once assisted Father in orchestrating the world's system.","TWN":"這是我之前幫忙父親調整世界這個系統時，父親替我取的稱號。"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"아버지께서 주신 내 본래 이름은 테라브레인 입실론 타입 – 001 인과계산기.","JPN":"父に与えられた本当の名は、テラブレイン・イプシロンタイプ – 001 因果計算機。","ENG":"The original name Father had given me was Terrabrain Upsilon Type–001: Causal Calculator.","TWN":"父親原本給我取的名字是，特拉大腦 Υ型 – 001因果計算機。"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"한 때 실패하고 버려졌으나…… 다시 돌아온 탕아이며……","JPN":"一時失敗して捨てられたが……再び戻ってきた蕩児であり……","ENG":"Once discarded as a failure, but now back as his prodigal son...","TWN":"曾經一度失敗後被拋棄……現在又再度回歸……"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"나약하고 물러 빠진 내 아버지가 사명을 이룰 수 있도록, 어둠 속에서 끊어진 인과의 실을 잇는 자다.","JPN":"脆弱で女々しい我が父が使命を果たせるよう、闇の中で途切れた因果の糸をつなぐ者だ。","ENG":"I am the one who binds the frayed thread of causality in the dark so that my frail and withdrawn father can complete his mission.","TWN":"我要從黑暗中將斷掉的因果線接上，讓懦弱的父親能夠完成使命。"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};